INSERT INTO course_instructions (id, role, budget, project_risk, case_study, requirement, about_course) VALUES
('ci-028', 'Học viên là nhạc công mới bắt đầu', 'Chi phí mua đàn từ 1-2 triệu VNĐ.', 'Rủi ro: Bỏ cuộc giữa chừng do đau tay.', 'Tự đệm hát được 5 bài hát phổ biến trong 30 ngày.', 'Có đàn Guitar (Acoustic hoặc Classic).', 'Học Guitar đệm hát căn bản dành cho người chưa biết gì.'),
('ci-029', 'Học viên là thí sinh luyện thi IELTS', 'Lệ phí thi: ~4.7 triệu VNĐ. Cần chuẩn bị kỹ.', 'Rủi ro: Không đạt target band score do thiếu từ vựng.', 'Giải quyết các dạng bài Listening & Reading khó nhất.', 'Tiếng Anh cơ bản (Pre-Intermediate).', 'Luyện thi IELTS chuyên sâu: Đột phá Band 7.0+'),
('ci-030', 'Học viên là chủ bếp gia đình', 'Ngân sách đi chợ hàng ngày.', 'Rủi ro: Chế biến sai cách làm mất dinh dưỡng.', 'Thực hiện thực đơn 10 món Á-Âu cao cấp tại nhà.', 'Bếp và các dụng cụ nấu ăn cơ bản.', 'Nghệ thuật nấu ăn chuyên nghiệp cho gia đình.'),
('ci-031', 'Học viên là 3D Modeler cho game', 'Máy tính cần có Card đồ họa rời.', 'Rủi ro: Render lỗi, máy treo do model quá nặng.', 'Tạo hình nhân vật hoạt hình hoàn chỉnh trong Blender.', 'Sử dụng chuột có con lăn, cài sẵn Blender.', 'Học Blender 3D: Từ khối cơ bản đến nhân vật hoàn chỉnh.'),
('ci-032', 'Học viên là nhân viên Marketing Agency', 'Ngân sách chạy Ads: 5 triệu VNĐ thử nghiệm.', 'Rủi ro: Giá thầu cao, không ra đơn hàng.', 'Xây dựng chiến dịch Facebook & Google Ads từ A-Z.', 'Có tài khoản Facebook cá nhân và thẻ Visa.', 'Digital Marketing thực chiến: Đột phá doanh số.'),
('ci-033', 'Học viên là người đi làm muốn học tiếng Nhật', 'Sách giáo khoa Minna no Nihongo.', 'Rủi ro: Quên chữ Hán (Kanji).', 'Giao tiếp cơ bản và thi đỗ chứng chỉ N5.', 'Kiên trì 30 phút mỗi ngày.', 'Tiếng Nhật cho người mới bắt đầu: Chinh phục N5.'),
('ci-034', 'Học viên là Scrum Master của một team Dev', 'Công cụ: Jira, Trello.', 'Rủi ro: Team không hiểu quy trình, deadline trễ.', 'Vận hành một Sprint 2 tuần hiệu quả.', 'Đang làm việc trong môi trường dự án phần mềm.', 'Quản trị dự án theo mô hình Agile/Scrum.'),
('ci-035', 'Học viên là người yêu thích nhiếp ảnh', 'Phần mềm Adobe Photoshop.', 'Rủi ro: Chỉnh sửa quá đà làm mất nét tự nhiên.', 'Retouch 20 ảnh chân dung và phong cảnh chuyên nghiệp.', 'Máy tính cài Photoshop (bản CC).', 'Làm chủ Photoshop CC: Từ cơ bản đến nâng cao.'),
('ci-036', 'Học viên là Founder dự án mới', 'Vốn tự có hoặc gọi vốn hạt giống.', 'Rủi ro: Cạn tiền (Burn rate cao) trước khi có khách.', 'Xây dựng Business Model Canvas cho dự án thực tế.', 'Có ý tưởng kinh doanh cụ thể.', 'Startup 101: Cách xây dựng doanh nghiệp từ con số 0.'),
('ci-037', 'Học viên là nhân viên văn phòng', 'Phần mềm Microsoft Excel.', 'Rủi ro: Sai sót công thức dẫn đến sai báo cáo.', 'Tự động hóa báo cáo doanh thu hàng tháng.', 'Cài đặt Microsoft Office.', 'Excel từ cơ bản đến chuyên gia: Dashboard & VBA.');
INSERT INTO course_instructions (id, role, budget, project_risk, case_study, requirement, about_course) VALUES
('ci-038', 'Học viên là AI Developer xây dựng Chatbot cho doanh nghiệp', 'Sử dụng API OpenAI (ngân sách 50 USD trải nghiệm).', 'Rủi ro: Model bị ảo tưởng (hallucination), lộ dữ liệu nhạy cảm.', 'Xây dựng Customer Support Bot tích hợp dữ liệu nội bộ công ty.', 'Biết Python cơ bản, có tài khoản OpenAI.', 'Mastering LLMs: Xây dựng ứng dụng với LangChain và Vector Database.'),
('ci-039', 'Học viên là Marketer muốn tối ưu hiệu suất bằng AI', 'Sử dụng công cụ Free/Freemium (ChatGPT, Midjourney).', 'Rủi ro: Nội dung thiếu tính nhân bản, bản quyền hình ảnh.', 'Tạo chiến dịch Marketing hoàn chỉnh (Text + Image) trong 1 giờ.', 'Không cần biết code.', 'Prompt Engineering toàn tập: Từ Zero đến Hero.'),
('ci-040', 'Học viên là Data Scientist triển khai model lên Production', 'Sử dụng Docker và AWS (ngân sách 20 USD).', 'Rủi ro: Model drift (giảm độ chính xác theo thời gian).', 'Thiết lập pipeline tự động training và deploy model nhận diện khuôn mặt.', 'Biết Python và cơ bản về Cloud.', 'MLOps: Quy trình triển khai và quản lý mô hình học máy.'),
('ci-041', 'Học viên là Creative Designer sử dụng công cụ AI sáng tạo', 'Ngân sách mua gói Stable Diffusion hoặc Adobe Firefly.', 'Rủi ro: Khó kiểm soát chi tiết nhỏ trong ảnh tạo ra.', 'Thiết kế bộ nhận diện thương hiệu hoàn toàn bằng Generative AI.', 'Đam mê nghệ thuật và công nghệ.', 'Generative AI cho Designer: Stable Diffusion & Midjourney.'),
('ci-042', 'Học viên là kỹ sư muốn hiểu bản chất toán học của AI', 'Chỉ cần giấy, bút và máy tính bỏ túi.', 'Rủi ro: Kiến thức trừu tượng, dễ gây nản lòng.', 'Chứng minh và lập trình thuật toán Backpropagation bằng tay.', 'Kiến thức toán cấp 3 vững.', 'Toán học cho Machine Learning: Đại số tuyến tính & Giải tích.');
INSERT INTO courses (id, title, author, course_sub, description, price, language, level, category, path, filename, instructor_id, course_instruction_id) VALUES
('crs-028', 'Guitar Đệm Hát Căn Bản', 'Sơn Guitar', 'Tự học guitar nhanh chóng cho người mới', 'Bạn sẽ học cách bấm hợp âm, các điệu quạt chả và cách bắt tông bài hát.', 600000.00, 'English', 'Beginner Level', 'Music', 'https://img-c.udemycdn.com/course/480x270/42271_9b01_10.jpg', 'course-guitar.jpg', 'usr-inst-013', 'ci-028'),
('crs-029', 'IELTS Writing & Speaking Breakthrough', 'Lan IELTS', 'Nâng band điểm với phương pháp Logical Thinking', 'Tập trung vào các tiêu chí chấm điểm của giám khảo và cách lên ý tưởng cho bài thi.', 1800000.00, 'English', 'Intermediate Level', 'Language', 'https://img-c.udemycdn.com/course/480x270/955220_9476_2.jpg', 'course-ielts.jpg', 'usr-inst-014', 'ci-029'),
('crs-030', 'Bếp Trưởng Tại Gia', 'Minh Chef', 'Nấu ăn ngon như nhà hàng 5 sao', 'Hướng dẫn kỹ thuật cắt thái, tẩm ướp và trang trí món ăn đỉnh cao.', 750000.00, 'English', 'All Level', 'Lifestyle', 'https://img-c.udemycdn.com/course/480x270/1141154_90e0_8.jpg', 'course-cooking.jpg', 'usr-inst-015', 'ci-030'),
('crs-031', 'Blender 3D: Build Your World', 'An Blender', 'Học thiết kế 3D chuyên nghiệp miễn phí', 'Làm chủ Blender để tạo ra các asset cho game và phim hoạt hình.', 1500000.00, 'English', 'Beginner Level', 'Design', 'https://img-c.udemycdn.com/course/480x270/3116330_56c7_10.jpg', 'course-blender.jpg', 'usr-inst-016', 'ci-031'),
('crs-032', 'Facebook Ads Mastery 2024', 'Tú Marketing', 'Chinh phục quảng cáo Facebook từ A-Z', 'Cập nhật các thuật toán mới nhất, cách chạy chuyển đổi và tối ưu ngân sách.', 1200000.00, 'English', 'Intermediate Level', 'Marketing', 'https://img-c.udemycdn.com/course/480x270/1318258_3313_3.jpg', 'course-fb-ads.jpg', 'usr-inst-017', 'ci-032'),
('crs-033', 'Tiếng Nhật Giao Tiếp N5', 'Quỳnh N3', 'Nền tảng vững chắc cho người học tiếng Nhật', 'Học 2 bảng chữ cái, 100 Kanji và các mẫu câu giao tiếp đời sống.', 900000.00, 'English', 'Beginner Level', 'Language', 'https://img-c.udemycdn.com/course/480x270/1410122_9443_2.jpg', 'course-japanese.jpg', 'usr-inst-018', 'ci-033'),
('crs-034', 'Agile & Scrum Certified', 'Đức Agile', 'Quản lý dự án linh hoạt trong kỷ nguyên số', 'Học cách vận hành team hiệu quả, giảm thiểu lãng phí và tăng tốc độ ra mắt sản phẩm.', 2100000.00, 'English', 'Expert', 'Business', 'https://img-c.udemycdn.com/course/480x270/1218636_19b8_10.jpg', 'course-agile.jpg', 'usr-inst-019', 'ci-034'),
('crs-035', 'Photoshop Chỉnh Sửa Ảnh Chuyên Nghiệp', 'Trang Photoshop', 'Trở thành phù thủy hình ảnh trong 30 ngày', 'Cắt ghép, phục chế ảnh cũ và blend màu nghệ thuật bằng Photoshop.', 850000.00, 'English', 'All Level', 'Design', 'https://img-c.udemycdn.com/course/480x270/1046722_cbd4_3.jpg', 'course-ps.jpg', 'usr-inst-020', 'ci-035'),
('crs-036', 'Hành Trình Khởi Nghiệp (Startup)', 'Huy Startup', 'Từ ý tưởng đến mô hình kinh doanh triệu đô', 'Cách tìm thị trường ngách, gọi vốn và quản trị nhân sự trong giai đoạn đầu.', 1350000.00, 'English', 'All Level', 'Business', 'https://img-c.udemycdn.com/course/480x270/2232814_2969_2.jpg', 'course-startup.jpg', 'usr-inst-021', 'ci-036'),
('crs-037', 'Master Excel: Data Analysis', 'Ngọc Excel', 'Biến dữ liệu thành thông tin giá trị', 'Thành thạo Pivot Table, Power Query và các hàm Excel nâng cao.', 550000.00, 'English', 'Intermediate Level', 'Data Science', 'https://img-c.udemycdn.com/course/480x270/1023240_ad9b.jpg', 'course-excel-pro.jpg', 'usr-inst-022', 'ci-037');
INSERT INTO courses (id, title, author, course_sub, description, price, language, level, category, path, filename, instructor_id, course_instruction_id) VALUES
('crs-038', 'LangChain & Vector Databases', 'Phạm GenAI', 'Xây dựng ứng dụng AI thế hệ mới với LLMs', 'Học cách kết nối sức mạnh của GPT-4 với dữ liệu riêng của bạn bằng LangChain, Pinecone và ChromaDB.', 2500000.00, 'English', 'Intermediate Level', 'AI', 'https://img-c.udemycdn.com/course/480x270/5356172_9d86_5.jpg', 'course-langchain.jpg', 'usr-inst-023', 'ci-038'),
('crs-039', 'Prompt Engineering cho mọi ngành nghề', 'Lê Prompt', 'Làm chủ nghệ thuật giao tiếp với trí tuệ nhân tạo', 'Cách viết câu lệnh (prompt) tối ưu cho ChatGPT, Claude, Bard để tăng 300% hiệu suất công việc.', 499000.00, 'English', 'Beginner Level', 'AI', 'https://img-c.udemycdn.com/course/480x270/5263606_4e34_3.jpg', 'course-prompt.jpg', 'usr-inst-024', 'ci-039'),
('crs-040', 'MLOps: Deploying ML Models', 'Vũ MLOps', 'Đưa mô hình AI từ Notebook ra thực tế', 'Học cách sử dụng Docker, Kubernetes, MLflow và GitHub Actions để vận hành hệ thống AI chuyên nghiệp.', 1990000.00, 'English', 'Expert', 'AI', 'https://img-c.udemycdn.com/course/480x270/4636306_5d37_5.jpg', 'course-mlops.jpg', 'usr-inst-027', 'ci-040'),
('crs-041', 'Nghệ thuật AI với Stable Diffusion', 'Phạm GenAI', 'Tạo hình ảnh đỉnh cao với Generative AI', 'Làm chủ Stable Diffusion, ControlNet và Lora để tạo ra những tác phẩm nghệ thuật không giới hạn.', 899000.00, 'English', 'All Level', 'Design', 'https://img-c.udemycdn.com/course/480x270/5123960_822e_2.jpg', 'course-stable-diffusion.jpg', 'usr-inst-023', 'ci-041'),
('crs-042', 'Toán học cho Trí tuệ nhân tạo', 'Đặng Toán Học', 'Nắm vững cốt lõi của Machine Learning', 'Đại số tuyến tính, giải tích đa biến và xác suất thống kê dành riêng cho kỹ sư AI.', 1100000.00, 'English', 'Intermediate Level', 'AI', 'https://img-c.udemycdn.com/course/480x270/2026116_7936_2.jpg', 'course-math-ai.jpg', 'usr-inst-026', 'ci-042'),
('crs-043', 'Natural Language Processing (NLP) Pro', 'Lê Prompt', 'Xây dựng hệ thống phân tích ngôn ngữ tự nhiên', 'Từ RNN, LSTM đến Transformer và BERT. Ứng dụng trong phân tích cảm xúc và dịch máy.', 1600000.00, 'English', 'Expert', 'AI', 'https://img-c.udemycdn.com/course/480x270/1126388_527f_4.jpg', 'course-nlp.jpg', 'usr-inst-024', 'ci-038'),
('crs-044', 'AI cho doanh nghiệp & Quản lý', 'Vũ MLOps', 'Chiến lược tích hợp AI vào quy trình kinh doanh', 'Dành cho Manager/Leader: Cách chọn bài toán AI phù hợp và đánh giá hiệu quả đầu tư (ROI).', 1300000.00, 'English', 'All Level', 'Business', 'https://img-c.udemycdn.com/course/480x270/5316330_56c7_10.jpg', 'course-ai-biz.jpg', 'usr-inst-027', 'ci-040');
